		return m, m.confirmAction(fmt.Sprintf("start over plan '%s'? this resets the branch.", planName), startOverAction)

	case "toggle_auto_advance":
		if m.appConfig == nil {
			return m, nil
		}
		m.appConfig.AutoAdvanceWaves = !m.appConfig.AutoAdvanceWaves
